package sqlite

import (
	"database/sql"
	"fmt"
	"time"

	"atena-label/internal/entity"
)

type ContactRepo struct {
	db *sql.DB
}

func NewContactRepo(db *sql.DB) *ContactRepo {
	return &ContactRepo{db: db}
}

func (r *ContactRepo) FindAll(groupID string) ([]entity.Contact, error) {
	var (
		rows *sql.Rows
		err  error
	)
	if groupID == "" {
		rows, err = r.db.Query(`SELECT id, family_name, given_name, family_name_kana, given_name_kana,
			honorific, postal_code, prefecture, city, street, building, company, department, notes,
			created_at, updated_at FROM contacts ORDER BY family_name_kana, given_name_kana`)
	} else {
		rows, err = r.db.Query(`SELECT c.id, c.family_name, c.given_name, c.family_name_kana, c.given_name_kana,
			c.honorific, c.postal_code, c.prefecture, c.city, c.street, c.building, c.company, c.department, c.notes,
			c.created_at, c.updated_at
			FROM contacts c
			JOIN contact_groups cg ON c.id = cg.contact_id
			WHERE cg.group_id = ?
			ORDER BY c.family_name_kana, c.given_name_kana`, groupID)
	}
	if err != nil {
		return nil, fmt.Errorf("find all contacts: %w", err)
	}
	defer rows.Close()
	return scanContacts(rows)
}

func (r *ContactRepo) FindByID(id string) (*entity.Contact, error) {
	row := r.db.QueryRow(`SELECT id, family_name, given_name, family_name_kana, given_name_kana,
		honorific, postal_code, prefecture, city, street, building, company, department, notes,
		created_at, updated_at FROM contacts WHERE id = ?`, id)
	c, err := scanContact(row)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	return c, err
}

func (r *ContactRepo) Create(c *entity.Contact) error {
	now := time.Now()
	c.CreatedAt = now
	c.UpdatedAt = now
	_, err := r.db.Exec(`INSERT INTO contacts
		(id, family_name, given_name, family_name_kana, given_name_kana, honorific,
		postal_code, prefecture, city, street, building, company, department, notes, created_at, updated_at)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		c.ID, c.FamilyName, c.GivenName, c.FamilyNameKana, c.GivenNameKana, c.Honorific,
		c.PostalCode, c.Prefecture, c.City, c.Street, c.Building, c.Company, c.Department, c.Notes,
		c.CreatedAt, c.UpdatedAt)
	if err != nil {
		return fmt.Errorf("create contact: %w", err)
	}
	return nil
}

func (r *ContactRepo) Update(c *entity.Contact) error {
	c.UpdatedAt = time.Now()
	result, err := r.db.Exec(`UPDATE contacts SET
		family_name=?, given_name=?, family_name_kana=?, given_name_kana=?, honorific=?,
		postal_code=?, prefecture=?, city=?, street=?, building=?, company=?, department=?, notes=?, updated_at=?
		WHERE id=?`,
		c.FamilyName, c.GivenName, c.FamilyNameKana, c.GivenNameKana, c.Honorific,
		c.PostalCode, c.Prefecture, c.City, c.Street, c.Building, c.Company, c.Department, c.Notes,
		c.UpdatedAt, c.ID)
	if err != nil {
		return fmt.Errorf("update contact: %w", err)
	}
	n, err := result.RowsAffected()
	if err != nil {
		return fmt.Errorf("update contact rows affected: %w", err)
	}
	if n == 0 {
		return fmt.Errorf("update contact: not found id=%s", c.ID)
	}
	return nil
}

func (r *ContactRepo) Delete(id string) error {
	_, err := r.db.Exec(`DELETE FROM contacts WHERE id = ?`, id)
	if err != nil {
		return fmt.Errorf("delete contact: %w", err)
	}
	return nil
}

func (r *ContactRepo) Search(query string) ([]entity.Contact, error) {
	like := "%" + query + "%"
	rows, err := r.db.Query(`SELECT id, family_name, given_name, family_name_kana, given_name_kana,
		honorific, postal_code, prefecture, city, street, building, company, department, notes,
		created_at, updated_at FROM contacts
		WHERE family_name LIKE ? OR given_name LIKE ? OR family_name_kana LIKE ? OR given_name_kana LIKE ?
		OR company LIKE ? OR postal_code LIKE ? OR city LIKE ?
		ORDER BY family_name_kana, given_name_kana`,
		like, like, like, like, like, like, like)
	if err != nil {
		return nil, fmt.Errorf("search contacts: %w", err)
	}
	defer rows.Close()
	return scanContacts(rows)
}

func scanContacts(rows *sql.Rows) ([]entity.Contact, error) {
	var contacts []entity.Contact
	for rows.Next() {
		c := entity.Contact{}
		if err := rows.Scan(&c.ID, &c.FamilyName, &c.GivenName, &c.FamilyNameKana, &c.GivenNameKana,
			&c.Honorific, &c.PostalCode, &c.Prefecture, &c.City, &c.Street, &c.Building,
			&c.Company, &c.Department, &c.Notes, &c.CreatedAt, &c.UpdatedAt); err != nil {
			return nil, err
		}
		contacts = append(contacts, c)
	}
	if contacts == nil {
		contacts = []entity.Contact{}
	}
	return contacts, rows.Err()
}

func scanContact(row *sql.Row) (*entity.Contact, error) {
	c := &entity.Contact{}
	err := row.Scan(&c.ID, &c.FamilyName, &c.GivenName, &c.FamilyNameKana, &c.GivenNameKana,
		&c.Honorific, &c.PostalCode, &c.Prefecture, &c.City, &c.Street, &c.Building,
		&c.Company, &c.Department, &c.Notes, &c.CreatedAt, &c.UpdatedAt)
	if err != nil {
		return nil, err
	}
	return c, nil
}

import { useEffect, useRef, useState } from 'react'
import { GetContacts, GetGroups, DeleteContacts, SearchContacts } from '../../../wailsjs/go/main/App'
import { useContactStore } from '../../stores/contactStore'
import type { Group } from '../../types'
import ContactEditModal from './ContactEditModal'
import type { Contact } from '../../types'

export default function ContactList() {
  const {
    contacts,
    selectedIds,
    currentGroupId,
    searchQuery,
    setContacts,
    toggleSelected,
    selectAll,
    clearSelection,
    setCurrentGroupId,
    setSearchQuery,
  } = useContactStore()

  const [groups, setGroups] = useState<Group[]>([])
  const [loading, setLoading] = useState(false)
  const [editTarget, setEditTarget] = useState<Contact | null | undefined>(undefined)
  // undefined = モーダル非表示, null = 新規作成, Contact = 編集

  const requestIdRef = useRef(0)

  // グループ一覧取得
  useEffect(() => {
    GetGroups().then(setGroups).catch(console.error)
  }, [])

  // 連絡先一覧取得 (競合状態を防ぐためリクエストIDで管理)
  useEffect(() => {
    const requestId = ++requestIdRef.current
    setLoading(true)
    const fetch = searchQuery
      ? SearchContacts(searchQuery)
      : GetContacts(currentGroupId)
    fetch
      .then((result) => {
        if (requestId === requestIdRef.current) {
          setContacts(result)
        }
      })
      .catch(console.error)
      .finally(() => {
        if (requestId === requestIdRef.current) {
          setLoading(false)
        }
      })
  }, [currentGroupId, searchQuery])

  const refreshContacts = async () => {
    const result = searchQuery
      ? await SearchContacts(searchQuery)
      : await GetContacts(currentGroupId)
    setContacts(result)
  }

  const handleDelete = async () => {
    if (selectedIds.size === 0) return
    const ids = Array.from(selectedIds)
    await DeleteContacts(ids)
    clearSelection()
    await refreshContacts()
  }

  const handleSaved = async () => {
    setEditTarget(undefined)
    clearSelection()
    await refreshContacts()
  }

  const tabs = [{ id: '', name: 'すべて' }, ...groups]

  return (
    <div className="flex flex-col h-full">
      {/* 検索バー */}
      <div className="p-3 border-b border-gray-200">
        <input
          type="text"
          placeholder="検索..."
          value={searchQuery}
          onChange={(e) => {
            setSearchQuery(e.target.value)
            clearSelection()
          }}
          className="w-full px-3 py-1.5 text-sm border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      {/* グループタブ */}
      <div className="flex overflow-x-auto border-b border-gray-200 px-2 pt-1 gap-1">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => {
              setCurrentGroupId(tab.id)
              setSearchQuery('')
              clearSelection()
            }}
            className={`px-3 py-1.5 text-xs rounded-t-md whitespace-nowrap transition-colors ${
              currentGroupId === tab.id && !searchQuery
                ? 'bg-blue-50 text-blue-700 font-medium border-b-2 border-blue-500'
                : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            {tab.name}
          </button>
        ))}
      </div>

      {/* 全選択/全解除 */}
      <div className="flex items-center justify-between px-3 py-1.5 border-b border-gray-100 text-xs text-gray-500">
        <span>{selectedIds.size > 0 ? `${selectedIds.size} 件選択中` : `${contacts.length} 件`}</span>
        <div className="flex gap-2">
          <button onClick={selectAll} className="hover:text-blue-600">全選択</button>
          <button onClick={clearSelection} className="hover:text-blue-600">解除</button>
        </div>
      </div>

      {/* 連絡先リスト */}
      <div className="flex-1 overflow-y-auto">
        {loading && (
          <div className="text-center py-8 text-sm text-gray-400">読み込み中...</div>
        )}
        {!loading && contacts.length === 0 && (
          <div className="text-center py-8 text-sm text-gray-400">
            {searchQuery ? '検索結果がありません' : '連絡先がありません'}
          </div>
        )}
        {!loading && contacts.map((c) => (
          <div
            key={c.id}
            onDoubleClick={() => setEditTarget(c)}
            className={`flex items-start gap-2 px-3 py-2.5 border-b border-gray-100 cursor-pointer hover:bg-gray-50 ${
              selectedIds.has(c.id) ? 'bg-blue-50' : ''
            }`}
          >
            <input
              type="checkbox"
              checked={selectedIds.has(c.id)}
              onChange={() => toggleSelected(c.id)}
              onClick={(e) => e.stopPropagation()}
              className="mt-1 h-3.5 w-3.5 accent-blue-600"
            />
            <div className="flex-1 min-w-0">
              <div className="flex items-baseline gap-1">
                <span className="text-sm font-medium text-gray-800">
                  {c.familyName} {c.givenName}
                </span>
                <span className="text-xs text-gray-400">{c.honorific}</span>
              </div>
              {c.company && (
                <div className="text-xs text-gray-500 truncate">{c.company}</div>
              )}
              <div className="text-xs text-gray-400 truncate">
                {c.postalCode && `〒${c.postalCode} `}
                {c.prefecture}{c.city}{c.street}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* フッターボタン */}
      <div className="p-2 border-t border-gray-200 flex gap-2">
        <button
          onClick={() => setEditTarget(null)}
          className="flex-1 py-1.5 text-sm bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors"
        >
          + 新規追加
        </button>
        {selectedIds.size > 0 && (
          <button
            onClick={handleDelete}
            className="px-3 py-1.5 text-sm bg-red-50 text-red-600 border border-red-200 rounded-md hover:bg-red-100 transition-colors"
          >
            削除 ({selectedIds.size})
          </button>
        )}
      </div>

      {/* 編集モーダル */}
      {editTarget !== undefined && (
        <ContactEditModal
          contact={editTarget ?? undefined}
          onClose={() => setEditTarget(undefined)}
          onSaved={handleSaved}
        />
      )}
    </div>
  )
}

