	}
	return ""
}

func rowToContact(row []string, lineNum int) (entity.Contact, error) {
	if len(row) < 1 {
		return entity.Contact{}, fmt.Errorf("行 %d: データが空です", lineNum)
	}

	honorific := col(row, 4)
	if honorific == "" {
		honorific = "様"
	}

	return entity.Contact{
		ID:             uuid.New().String(),
		FamilyName:     col(row, 0),
		GivenName:      col(row, 1),
		FamilyNameKana: col(row, 2),
		GivenNameKana:  col(row, 3),
		Honorific:      honorific,
		PostalCode:     col(row, 5),
		Prefecture:     col(row, 6),
		City:           col(row, 7),
		Street:         col(row, 8),
		Building:       col(row, 9),
		Company:        col(row, 10),
		Department:     col(row, 11),
		Notes:          col(row, 12),
	}, nil
}

func contactToRow(c entity.Contact) []string {
	return []string{
		c.FamilyName,
		c.GivenName,
		c.FamilyNameKana,
		c.GivenNameKana,
		c.Honorific,
		c.PostalCode,
		c.Prefecture,
		c.City,
		c.Street,
		c.Building,
		c.Company,
		c.Department,
		c.Notes,
	}
}

